<?php $title='Channels';require __DIR__.'/partials/header.php';?><div class="row g-4"><div class="col-lg-5"><div class="card"><div class="card-body"><h1 class="h4">New channel</h1><form method="post" action="/channels"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input class="form-control mb-2" name="name" placeholder="Name" required><textarea class="form-control mb-2" name="description" placeholder="Description"></textarea><input class="form-control mb-2" name="rtmp_url" placeholder="RTMP URL" required><input class="form-control mb-2" name="stream_key" placeholder="Stream key" required><div class="form-check mb-3"><input class="form-check-input" type="checkbox" name="is_default" id="default"><label class="form-check-label" for="default">Default channel</label></div><button class="btn btn-primary">Save channel</button></form></div></div></div><div class="col-lg-7"><h1 class="h4">Channels</h1><?php foreach($channels as $c):?><div class="card mb-2"><div class="card-body"><div class="d-flex justify-content-between"><div><strong><?=e($c['name'])?></strong> <?=($c['enabled']??1)?'<span class="badge text-bg-success">Enabled</span>':'<span class="badge text-bg-secondary">Disabled</span>'?><div class="small text-secondary"><?=e($c['rtmp_url'])?></div></div><div class="btn-group"><button class="btn btn-sm btn-outline-primary" data-bs-toggle="collapse" data-bs-target="#edit-<?=$c['id']?>">Edit</button><form method="post" action="/channels/toggle"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input type="hidden" name="channel_id" value="<?=$c['id']?>"><button class="btn btn-sm btn-outline-secondary"><?=($c['enabled']??1)?'Disable':'Enable'?></button></form><form method="post" action="/channels/duplicate"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input type="hidden" name="channel_id" value="<?=$c['id']?>"><button class="btn btn-sm btn-outline-secondary">Duplicate</button></form><form method="post" action=